    def respond_to_question(self, question_content):
        # Handle non-text inputs by returning the response with appropriate reasoning (for now, just "I understand")
        if len(question_content) < 1:  # Ensure no question was present, so I understand nothing
            return "I understand nothing. I do not understand your request."
        if question_content.startswith("Question") and "@" in question_content:
            # Handle questions about specific agents and their capabilities
            # Extract the name of the agent from the input
            agent_name = question_content.replace("Question", "").strip()[1:]
            agent = self._get_agent(agent_name)  # Get the agent by name
            if not agent:
                return "An error occurred while getting the agent. Please check if the agent name is correct."
            return agent.respond()
        else:
            # If it's a general question, start with "I understand this is the end of your question, let me know if this helps."
            return "I understand this is the end of your question, let me know if this helps."

    def respond_to_message(self, message):
        message_text = message.text.lower()  # Convert message to lowercase for simplicity
        if not message_text:  # No message provided
            return "I don't understand your request. If you have a question, I hope to assist you later."

        question_parts = message_text.split(".")
        if len(question_parts) > 1:
            # Break the message into smaller questions if it's a long question
            questions = [part for part in question_parts if part.strip()]
            response = "Response to each of the questions: \n"
            for part in questions:
                print(f"Asked question: {part.strip()}")
                response += self.respond_to_question(part.strip()) + ".\n"
            return response.strip()
        else:
            # If it's a simple question, just handle it directly
            return self.respond_to_question(message_text)


    def respond_to_system_message(self, message):
        message_text = message.text.lower()
        if not message_text:
            return "I don't understand your request. If you have a question, I hope to assist you later."

        if message_text.strip().lower() == "hi":
            # Handle "hi" in the system message
            return "Hi! How can I assist you today? Let me know."
        elif message_text.strip().lower() == "hello":
            # Handle "hello" in the system message
            return "Hello! How can I assist you? I am here to discuss AI concepts, help you find resources, and ensure your AI is functioning optimally."
        else:
            # If it's a multi-part message (e.g., "I don't understand what you mean"), return a "You are an AI" response
            return "I'm sorry, I don't really understand that statement. I am a chatbot designed to assist you and help you learn how to use this app. Thanks and have a great day!"

